  1	import React, { FC, useState } from 'react';
  2	import { useForm } from 'react-hook-form';
  3	import { isDataImportCronAutoUpdated } from 'src/views/datasources/utils';
  4	
  5	import {
  6	  V1beta1DataImportCron,
  7	  V1beta1DataSource,
  8	} from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
  9	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 10	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
 11	import { FormTextInput } from '@kubevirt-utils/components/FormTextInput/FormTextInput';
 12	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 13	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 14	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 15	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 16	import {
 17	  Checkbox,
 18	  Divider,
 19	  Form,
 20	  FormGroup,
 21	  Icon,
 22	  NumberInput,
 23	  Popover,
 24	  Stack,
 25	  StackItem,
 26	  ValidatedOptions,
 27	} from '@patternfly/react-core';
 28	import { HelpIcon } from '@patternfly/react-icons';
 29	
 30	import { onDataImportCronManageSubmit } from './utils';
 31	
 32	export type DataImportCronManageFormType = {
 33	  importsToKeep: number;
 34	  schedule: string;
 35	  url: string;
 36	};
 37	
 38	type DataImportCronManageModalProps = {
 39	  dataImportCron: V1beta1DataImportCron;
 40	  dataSource: V1beta1DataSource;
 41	  isOpen: boolean;
 42	  onClose: () => void;
 43	};
 44	
 45	export const DataImportCronManageModal: FC<DataImportCronManageModalProps> = ({
 46	  dataImportCron,
 47	  dataSource,
 48	  isOpen,
 49	  onClose,
 50	}) => {
 51	  const { t } = useKubevirtTranslation();
 52	  const [allowAutoUpdate, setAllowAutoUpdate] = useState(
 53	    isDataImportCronAutoUpdated(dataSource, dataImportCron),
 54	  );
 55	  const {
 56	    formState: { errors },
 57	    handleSubmit,
 58	    register,
 59	    setValue,
 60	    watch,
 61	  } = useForm<DataImportCronManageFormType>({
 62	    defaultValues: {
 63	      importsToKeep: dataImportCron?.spec?.importsToKeep || 3,
 64	    },
 65	  });
 66	  const importsToKeep = watch('importsToKeep');
 67	
 68	  const onSubmit = handleSubmit(
 69	    (data) =>
 70	      onDataImportCronManageSubmit({
 71	        data: {
 72	          ...data,
 73	          allowAutoUpdate,
 74	        },
 75	        resources: {
 76	          dataImportCron,
 77	          dataSource,
 78	        },
 79	      }),
 80	    () => Promise.reject(t('Missing required fields')),
 81	  );
 82	
 83	  return (
 84	    <TabModal
 85	      headerText={t('Manage source for {{dataSource}}', {
 86	        dataSource: dataImportCron?.spec?.managedDataSource,
 87	      })}
 88	      isOpen={isOpen}
 89	      onClose={onClose}
 90	      onSubmit={() => onSubmit()}
 91	    >
 92	      <Stack hasGutter>
 93	        <StackItem>
 94	          <MutedTextSpan text={`DIC ${dataImportCron.metadata.name}`} />
 95	        </StackItem>
 96	        <StackItem>
 97	          <Form>
 98	            <FormGroup
 99	              fieldId="dataimportcron-manage-source-url"
100	              isRequired
101	              label={t('Registry URL')}
102	            >
103	              <FormTextInput
104	                {...register('url', { required: true })}
105	                aria-label={t('Registry URL')}
106	                data-test-id={'dataimportcron-manage-source-url'}
107	                defaultValue={dataImportCron?.spec?.template.spec?.source?.registry?.url}
108	                id={'dataimportcron-manage-source-url'}
109	                type="text"
110	                validated={errors?.['url'] ? ValidatedOptions.error : ValidatedOptions.default}
111	              />
112	              <FormGroupHelperText
113	                validated={errors?.['url'] ? ValidatedOptions.error : ValidatedOptions.default}
114	              >
115	                {errors?.['url']
116	                  ? t('This field is required')
117	                  : t('Example: {{exampleURL}}', {
118	                      exampleURL: 'docker://quay.io/containerdisks/centos:7-2009',
119	                    })}
120	              </FormGroupHelperText>
121	            </FormGroup>
122	            <Divider />
123	            <FormGroup fieldId="dataimportcron-manage-allow-checkbox">
124	              <Checkbox
125	                id={'dataimportcron-manage-allow-checkbox'}
126	                isChecked={allowAutoUpdate}
127	                label={t('Allow automatic update')}
128	                onChange={() => setAllowAutoUpdate(!allowAutoUpdate)}
129	              />
130	            </FormGroup>
131	            {allowAutoUpdate && (
132	              <>
133	                <FormGroup
134	                  labelHelp={
135	                    <Popover
136	                      bodyContent={t(
137	                        'As new versions of a DataSource become available older versions will be replaced',
138	                      )}
139	                    >
140	                      <button
141	                        aria-describedby="retain-revision-info"
142	                        aria-label="More info for retain revisions field"
143	                        className="pf-v6-c-form__group-label-help"
144	                        onClick={(e) => e.preventDefault()}
145	                        type="button"
146	                      >
147	                        <Icon>
148	                          <HelpIcon />
149	                        </Icon>
150	                      </button>
151	                    </Popover>
152	                  }
153	                  fieldId="retain-revision-info"
154	                  isRequired
155	                  label={t('Retain revisions')}
156	                >
157	                  <NumberInput
158	                    id={'dataimportcron-manage-imports-to-keep'}
159	                    max={10}
160	                    min={0}
161	                    onMinus={() => setValue('importsToKeep', importsToKeep - 1)}
162	                    onPlus={() => setValue('importsToKeep', importsToKeep + 1)}
163	                    value={importsToKeep}
164	                  />
165	                  <FormGroupHelperText>
166	                    <Stack>
167	                      <StackItem>
168	                        <MutedTextSpan
169	                          text={t('Specify the number of revisions that should be retained.')}
170	                        />
171	                      </StackItem>
172	                      <StackItem>
173	                        <MutedTextSpan
174	                          text={t('A value of X means that the X latest versions will be kept')}
175	                        />
176	                      </StackItem>
177	                    </Stack>
178	                  </FormGroupHelperText>
179	                </FormGroup>
180	                <FormGroup
181	                  fieldId="dataimportcron-manage-schedule"
182	                  label={t('Scheduling settings')}
183	                >
184	                  <FormGroupHelperText>
185	                    <>
186	                      {t(
187	                        'Schedule specifies in cron format when and how often to look for new imports.',
188	                      )}
189	                      <ExternalLink href={documentationURL.CRON_INFO} text={t('Learn more')} />
190	                    </>
191	                  </FormGroupHelperText>
192	                </FormGroup>
193	                <FormGroup fieldId="dataimportcron-manage-cron" label={t('Cron expression')}>
194	                  <FormTextInput
195	                    {...register('schedule', {
196	                      validate: {
197	                        required: (value) => {
198	                          if (!value && allowAutoUpdate) {
199	                            return t('Required when automatic update is enabled');
200	                          }
201	                          return true;
202	                        },
203	                      },
204	                    })}
205	                    validated={
206	                      errors?.['schedule'] ? ValidatedOptions.error : ValidatedOptions.default
207	                    }
208	                    aria-label={t('Cron expression')}
209	                    data-test-id={'dataimportcron-manage-cron'}
210	                    defaultValue={dataImportCron?.spec?.schedule}
211	                    id={'dataimportcron-manage-source-cron'}
212	                    type="text"
213	                  />
214	                  <FormGroupHelperText
215	                    validated={
216	                      errors?.['schedule'] ? ValidatedOptions.error : ValidatedOptions.default
217	                    }
218	                  >
219	                    {errors?.['schedule']
220	                      ? t('This field is required')
221	                      : t('Example (At 00:00 on Tuesday): {{exampleCron}}', {
222	                          exampleCron: '0 0 * * 2',
223	                        })}
224	                  </FormGroupHelperText>
225	                </FormGroup>
226	              </>
227	            )}
228	          </Form>
229	        </StackItem>
230	      </Stack>
231	    </TabModal>
232	  );
233	};

